const response = $input.first().json || {};
const registrationCountries = ["USA", "UK", "Canada", "Australia", "Germany", "France", "Netherlands", "Ireland", "Singapore", "Japan", "Sweden", "Norway", "New Zealand", "UAE"];
const aliases = {
  'UK': 'United Kingdom',
  'USA': 'United States',
  'US': 'United States',
  'HongKong': 'Hong Kong'
};
const normalize = (c) => aliases[c] || c;
const datasetCountries = registrationCountries.map(normalize);

const sourceMap = {
  'United Kingdom': {
    visa_type: 'UK Student Route Visa',
    processing_time: '3-8 weeks',
    visa_fee_inr: 52500,
    official_sources: [
      'https://www.gov.uk/student-visa',
      'https://www.gov.uk/graduate-visa'
    ],
    checklist: [
      { id: 'uk_1', category: 'Admission', item: 'CAS from UK university' },
      { id: 'uk_2', category: 'Financial', item: 'Proof of funds for tuition and living' },
      { id: 'uk_3', category: 'Identity', item: 'Valid passport and biometrics appointment' }
    ]
  },
  'United States': {
    visa_type: 'US F-1 Student Visa',
    processing_time: '2-8 weeks',
    visa_fee_inr: 15300,
    official_sources: [
      'https://travel.state.gov/content/travel/en/us-visas/study/student-visa.html',
      'https://www.uscis.gov/working-in-the-united-states/students-and-exchange-visitors'
    ],
    checklist: [
      { id: 'us_1', category: 'Admission', item: 'I-20 from SEVP-approved institution' },
      { id: 'us_2', category: 'Fees', item: 'SEVIS I-901 fee payment receipt' },
      { id: 'us_3', category: 'Interview', item: 'DS-160 and visa interview slot confirmation' }
    ]
  },
  'Canada': {
    visa_type: 'Canada Study Permit',
    processing_time: '4-12 weeks',
    visa_fee_inr: 9200,
    official_sources: [
      'https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit.html',
      'https://www.canada.ca/en/immigration-refugees-citizenship/services/study-canada/study-permit/get-documents.html'
    ],
    checklist: [
      { id: 'ca_1', category: 'Admission', item: 'Letter of Acceptance from DLI' },
      { id: 'ca_2', category: 'Financial', item: 'Proof of tuition and living funds' },
      { id: 'ca_3', category: 'Academic', item: 'Previous transcripts and language results' }
    ]
  },
  'Australia': {
    visa_type: 'Student Visa Subclass 500',
    processing_time: '4-10 weeks',
    visa_fee_inr: 89000,
    official_sources: [
      'https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-listing/student-500',
      'https://immi.homeaffairs.gov.au/visas/getting-a-visa/visa-processing-times/global-visa-processing-times'
    ],
    checklist: [
      { id: 'au_1', category: 'Admission', item: 'Confirmation of Enrolment (CoE)' },
      { id: 'au_2', category: 'Health', item: 'Overseas Student Health Cover (OSHC)' },
      { id: 'au_3', category: 'Financial', item: 'Genuine Student and funds evidence' }
    ]
  },
  'Germany': {
    visa_type: 'Germany National Student Visa',
    processing_time: '6-12 weeks',
    visa_fee_inr: 7500,
    official_sources: [
      'https://www.make-it-in-germany.com/en/visa-residence/types/studying',
      'https://india.diplo.de/in-en/service/-/2552164'
    ],
    checklist: [
      { id: 'de_1', category: 'Admission', item: 'University admission letter' },
      { id: 'de_2', category: 'Financial', item: 'Blocked account or scholarship proof' },
      { id: 'de_3', category: 'Health', item: 'Health insurance as required' }
    ]
  },
  'France': {
    visa_type: 'France Long-Stay Student Visa (VLS-TS)',
    processing_time: '3-8 weeks',
    visa_fee_inr: 9000,
    official_sources: [
      'https://www.service-public.fr/particuliers/vosdroits/F2231?lang=en',
      'https://www.campusfrance.org/en/student-long-stay-visa'
    ],
    checklist: [
      { id: 'fr_1', category: 'Admission', item: 'Campus France process completion' },
      { id: 'fr_2', category: 'Financial', item: 'Proof of accommodation and funds' },
      { id: 'fr_3', category: 'Identity', item: 'Passport and biometric appointment' }
    ]
  },
  'Netherlands': {
    visa_type: 'MVV + Residence Permit for Study',
    processing_time: '4-8 weeks',
    visa_fee_inr: 21000,
    official_sources: [
      'https://ind.nl/en/residence-permits/study',
      'https://www.studyinnl.org/plan-your-stay/visas-and-permits'
    ],
    checklist: [
      { id: 'nl_1', category: 'Admission', item: 'University admission and sponsor handling by institution' },
      { id: 'nl_2', category: 'Financial', item: 'Proof of sufficient means' },
      { id: 'nl_3', category: 'Identity', item: 'MVV/permit documents as instructed by IND' }
    ]
  },
  'Ireland': {
    visa_type: 'Ireland Long Stay Study Visa (D)',
    processing_time: '4-8 weeks',
    visa_fee_inr: 6000,
    official_sources: [
      'https://www.irishimmigration.ie/coming-to-study-in-ireland/',
      'https://www.irishimmigration.ie/how-to-become-a-citizen/your-visa-application/'
    ],
    checklist: [
      { id: 'ie_1', category: 'Admission', item: 'Letter of acceptance from listed education provider' },
      { id: 'ie_2', category: 'Financial', item: 'Evidence of tuition payment and maintenance funds' },
      { id: 'ie_3', category: 'Academic', item: 'Academic and language evidence' }
    ]
  },
  'Spain': {
    visa_type: 'Spain Student Visa',
    processing_time: '4-8 weeks',
    visa_fee_inr: 8000,
    official_sources: [
      'https://www.exteriores.gob.es/Embajadas/nuevadelhi/en/ServiciosConsulares/Paginas/Consular/Visado-de-estudios.aspx',
      'https://www.inclusion.gob.es/web/migraciones/w/students'
    ],
    checklist: [
      { id: 'es_1', category: 'Admission', item: 'Acceptance letter from authorized institution' },
      { id: 'es_2', category: 'Health', item: 'Medical certificate and health coverage' },
      { id: 'es_3', category: 'Criminal', item: 'Police clearance when applicable' }
    ]
  },
  'Italy': {
    visa_type: 'Italy Study Visa (Type D)',
    processing_time: '4-8 weeks',
    visa_fee_inr: 7000,
    official_sources: [
      'https://vistoperitalia.esteri.it/home/en',
      'https://studyinitaly.esteri.it/'
    ],
    checklist: [
      { id: 'it_1', category: 'Admission', item: 'University pre-enrolment and admission documents' },
      { id: 'it_2', category: 'Financial', item: 'Proof of means and accommodation' },
      { id: 'it_3', category: 'Identity', item: 'Valid passport and visa application pack' }
    ]
  },
  'Switzerland': {
    visa_type: 'Swiss Student Visa',
    processing_time: '6-12 weeks',
    visa_fee_inr: 9000,
    official_sources: [
      'https://www.sem.admin.ch/sem/en/home/themen/einreise/faq.html',
      'https://www.eda.admin.ch/countries/india/en/home/visa/entry-ch/up-90-days/where-to-apply-national.html'
    ],
    checklist: [
      { id: 'ch_1', category: 'Admission', item: 'University confirmation and study plan' },
      { id: 'ch_2', category: 'Financial', item: 'Proof of sufficient funds for stay' },
      { id: 'ch_3', category: 'Identity', item: 'National visa documents as per consulate' }
    ]
  },
  'Singapore': {
    visa_type: 'Student Pass',
    processing_time: '2-6 weeks',
    visa_fee_inr: 4000,
    official_sources: [
      'https://www.ica.gov.sg/reside/STP/apply',
      'https://www.ica.gov.sg/reside/STP/collect'
    ],
    checklist: [
      { id: 'sg_1', category: 'Admission', item: 'Accepted by approved institution and SOLAR registration' },
      { id: 'sg_2', category: 'Identity', item: 'Passport and digital photograph requirements' },
      { id: 'sg_3', category: 'Health', item: 'Medical requirements if requested' }
    ]
  }
};

const selectedCountries = datasetCountries.filter((c) => sourceMap[c]);
const finalCountries = selectedCountries.length ? selectedCountries : Object.keys(sourceMap);

const items = [];
for (const country of finalCountries) {
  const cfg = sourceMap[country];
  for (const [idx, url] of cfg.official_sources.entries()) {
    items.push({
      json: {
        country,
        source_url: url,
        source_index: idx + 1,
        official_link: cfg.official_sources[0],
        visa_type: cfg.visa_type,
        processing_time: cfg.processing_time,
        visa_fee_inr: cfg.visa_fee_inr,
        checklist: cfg.checklist
      }
    });
  }
}

return items;

const rows = $input.all();
const grouped = new Map();

for (const row of rows) {
  const j = row.json || {};
  const country = j.country;
  if (!country) continue;

  if (!grouped.has(country)) {
    grouped.set(country, {
      meta: {
        visa_type: j.visa_type || 'Student Visa',
        official_link: j.official_link || j.source_url || '',
        processing_time: j.processing_time || '',
        visa_fee_inr: Number(j.visa_fee_inr || 0),
        checklist: Array.isArray(j.checklist) ? j.checklist : []
      },
      snippets: []
    });
  }

  const raw = (j.body || j.data || '').toString();
  const text = raw
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 2000);

  const safeText = text || `Official guidance page fetched but parsing returned minimal text. Check source: ${j.source_url || ''}`;
  grouped.get(country).snippets.push(`Source ${j.source_index || 1}: ${j.source_url}\n\n${safeText}`);
}

const countries = {};
const documents = [];
for (const [country, val] of grouped.entries()) {
  countries[country] = val.meta;
  documents.push({
    country,
    filename: country.toLowerCase().replace(/[^a-z0-9]+/g, '_') + '_student_visa.md',
    official_link: val.meta.official_link,
    content: val.snippets.join('\n\n---\n\n').slice(0, 14000)
  });
}

return [{ json: { countries, documents } }];
